mapper.select:
select count(*) from code_node
where project_id = #{projectId} and version_id = #{versionId}
  and file_path is not null and file_path != '' and line_no is not null

select id, node_type, name, qualified_name, file_path, line_no, metadata_json from code_node
where project_id = #{projectId} and version_id = #{versionId}
  and node_type = 'API_ROUTE' and name like concat('%', #{apiPath}, '%')
order by name limit #{limit}

select n.id, n.node_type, n.name, n.qualified_name, n.file_path, n.line_no, n.metadata_json
from code_edge e join code_node n on e.to_node_id = n.id
where e.from_node_id = #{fromNodeId}
  and e.edge_type in
  #{t}
limit 80

select n.id, n.node_type, n.name, n.qualified_name, n.file_path, n.line_no, n.metadata_json
from code_edge e join code_node n on e.from_node_id = n.id
where e.to_node_id = #{toNodeId}
  and e.edge_type in
  #{t}
limit 80

select id, node_type, name, qualified_name, file_path, line_no, metadata_json from code_node
where project_id = #{projectId} and version_id = #{versionId}
  and node_type in
  #{t}
  and (name like concat('%', #{keyword}, '%') or qualified_name like concat('%', #{keyword}, '%'))
limit #{limit}

select id, node_type, name, qualified_name, file_path, line_no, metadata_json from code_node
where project_id = #{projectId} and version_id = #{versionId}
  and node_type in
  #{t}
  and (name like concat('%', #{keyword}, '%') or qualified_name like concat('%', #{keyword}, '%') or metadata_json like concat('%', #{keyword}, '%'))
limit #{limit}

select id from code_node
where project_id = #{projectId} and version_id = #{versionId}
  and node_type = 'METHOD' and name = #{methodName}
limit #{limit}

select id from code_node
where project_id = #{projectId} and version_id = #{versionId}
  and node_type = 'METHOD' and qualified_name = #{qualifiedName}
limit 1
